const SILENCE_MIN = 8 * 60 * 1000; // 8 minutos en ms
const MAX_MSGS = 12;

const chunks = [];
let current = null;

for (const row of items.map(i => i.json)) {
  if (!current || current.remote_jid !== row.remote_jid) {
    if (current) chunks.push(current);
    current = {
      remote_jid: row.remote_jid,
      rango_inicio: row.date_time,
      rango_fin: row.date_time,
      participantes: new Set([row.push_name || row.sender]),
      mensajes_ids: [row.id],
      texto_concatenado: `[${row.date_time} | ${row.push_name}] ${row.conversation}`
    };
    continue;
  }

  const prevTime = new Date(current.rango_fin);
  const thisTime = new Date(row.date_time);
  const gap = thisTime - prevTime;

  if (gap >= SILENCE_MIN || current.mensajes_ids.length >= MAX_MSGS) {
    chunks.push(current);
    current = {
      remote_jid: row.remote_jid,
      rango_inicio: row.date_time,
      rango_fin: row.date_time,
      participantes: new Set([row.push_name || row.sender]),
      mensajes_ids: [row.id],
      texto_concatenado: `[${row.date_time} | ${row.push_name}] ${row.conversation}`
    };
  } else {
    current.rango_fin = row.date_time;
    current.participantes.add(row.push_name || row.sender);
    current.mensajes_ids.push(row.id);
    current.texto_concatenado += `\n[${row.date_time} | ${row.push_name}] ${row.conversation}`;
  }
}
if (current) chunks.push(current);

return chunks.map(c => ({
  json: {
    remote_jid: c.remote_jid,
    rango_inicio: c.rango_inicio,
    rango_fin: c.rango_fin,
    participantes: Array.from(c.participantes),
    mensajes_ids: c.mensajes_ids,
    texto_concatenado: c.texto_concatenado
  }
}));
